var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"탄창이 바닥 날 때까지 쏴 버려!","JPN":"弾切れになるまで撃て！","ENG":"Shoot until you run out of bullets!","TWN":"開火到彈匣見底為止！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"달려드는 침식체들부터 저지해야 한다! 접근을 허용하지 마라!","JPN":"襲ってくる侵食体の阻止が先だ！　近づかせるな！","ENG":"Aim for the C.O.s charging in first! Don't let any of them in!","TWN":"優先解決撲過來的侵蝕體！別讓他們靠近！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"엇?","JPN":"おおっ？","ENG":"Huh?","TWN":"咦？"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"치, 침식 쐐기다!!","JPN":"し、侵食楔だ！！","ENG":"I-it's a Corrupted Wedge!","TWN":"侵，侵蝕釘！！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"침식 쐐기가 기지를 꿰뚫고 있어!","JPN":"侵食楔が基地を貫いているぞ！","ENG":"The Corrupted Wedge is piercing the base!","TWN":"侵蝕釘穿透了基地！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"다들 쐐기에 찔리지 않게 조심해! 스치기만 해도 급성 침식 증후군이……","JPN":"みんな楔に当たらないように注意しろ！　かするだけで急性侵食症候群が……","ENG":"Be careful not to get stabbed by the wedges! Even a graze will lead to acute Corruption Syndrome...","TWN":"注意別被釘子扎到！只要被擦傷就會出現侵蝕症候群……"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"으, 으아아아악!!","JPN":"う、うわああああっ！！","ENG":"AAAAAARGH!!","TWN":"呃，呃啊啊啊！！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L14_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"망할! 다들 죽고 싶어서 환장했어!?","JPN":"くそっ！　お前ら死にたくなったのか！？","ENG":"Ugh! Do you all have a death wish or something?!","TWN":"混蛋！你們是想找死嗎？！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L15_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"멍하게 있지 말고, 빨랑빨랑 함교로 대피하란 말이야!","JPN":"ぼーっとしていないで、早く艦橋に避難しろよ！","ENG":"Don't just stand there! Get in the ship already!","TWN":"別愣著，快點躲到艦橋上！"},"stage":{"bg":"CORRIDOR","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"제기랄, 녀석들이 우릴 체포하려 하지 않나, 갑자기 침식체들이 기습하질 않나!","JPN":"クソ！　奴らは逮捕しようとしてくるわ、いきなり侵食体に襲われるわ！","ENG":"Dammit. First these idiots try to arrest us, and then C.O.s ambush us out of nowhere!","TWN":"可惡，先是這些白癡保衛軍，然後又是侵蝕體！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"이봐, 마스터! 마스터는 뭐 알고 있는 거 없어!?","JPN":"おい、マスター！　マスターは何も知らないのか！？","ENG":"Hey, Master! Do you know anything about this?!","TWN":"喂，大姊！你是不是知道什麼？！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"일반적인 침식체는 작전을 이해할 지능이 없지.","JPN":"普通の侵食体に作戦を理解できる知能はない。","ENG":"Normally, C.O.s have no understanding of what tactics are.","TWN":"普通侵蝕體在作戰中沒有智力。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"이건 우두머리 노릇을 하고 있는 하얀 그림자의 명령이야.","JPN":"これはリーダー格の白いシャドウが命令を下しているんだ。","ENG":"This looks like an order from the white Shadow, their leader.","TWN":"這是帶頭的白色暗影的命令。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"상위종 그림자는 특유의 침식파로 하위 침식체들을 복종시킬 수 있으니까.","JPN":"上位種のシャドウは特有の侵食波で下位侵食体を服従させることができる。","ENG":"High-category Shadows have the ability to give orders to lower ones with their unique Corruption ray.","TWN":"高階暗影特有的侵蝕波可以對低階侵蝕體發號施令。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"아마 이곳을 습격한 건 그림자의 <color=#ffd34c>우선순위</color>가 네피림 고치에서 다른 것으로 바뀐 것일 수도 있겠군.","JPN":"おそらくここを襲ってきたということは、シャドウの<color=#ffd34c>優先順位</color>がネフィリムの繭から別のものに変わったとういことだろう。","ENG":"The reason why they are attacking this place is because the Shadow's <color=#ffd34c>priority</color> has changed from the Nephil cocoons to something else.","TWN":"會襲擊這裡，大概是因為那個暗影的<color=#ffd34c>首選</color>，從諾菲力繭變成了其他東西。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REBECCA_DELTA_NULL_NULL","text":{"KOREA":"우선순위가 바뀌었다고? 그게 무슨 소리야?","JPN":"優先順位が変わった？　それってどういうこと？","ENG":"Changed priorities? Care to explain?","TWN":"變成其他東西？那是什麼意思？"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"REBECCA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"글쎄? 딱히 그런 게 우리에게 중요한 문제는 아닐세.","JPN":"さあ？　我々にとってはさほど重要ではないのでな。","ENG":"I'm not sure. But it is not something that is of utmost importance to us right now.","TWN":"這個現在對我們不重要。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"중요한 건 저 그림자가 이 세계를 끝내 버리기 전에, 우린 항해에 필요한 물자들을 확보해야 한다는 거겠지.","JPN":"それより、あのシャドウが世界を終わらせる前に、航海に必要な物資を確保しなければ。","ENG":"What is important is that we must secure the necessary resources for our voyage before the Shadow ends this world.","TWN":"我們最重要的目的，便是在暗影徹底毀滅這個世界之前，儲備好航行需要的物資。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"사령관님, 생존한 대원들 전원, 아이기스에 탑승 완료하였습니다.","JPN":"司令官、生き残った隊員は全員、アイギスに搭乗完了しました。","ENG":"Commander, all surviving troops are onboard Aegis.","TWN":"司令官，倖存部隊已全部登上埃癸斯。"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"좋아, 기지 각 구역에 놓친 물자가 있는 지 마지막으로 확인해라!","JPN":"よし、基地の各区域に回収し損ねた物資かあるかどうか最後に確認しろ！","ENG":"Good. Lastly, check if there are any supplies we missed from each area!","TWN":"很好，最後確認一下基地各區域是否有漏下的物資！"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"그 후, 다음 방위선으로 이동할 준비를……","JPN":"そして、次の防衛線に移動する準備を……","ENG":"After that, prepare to move on to the next Defense L–","TWN":"之後，準備向下一個防線移動……"},"stage":{"bg":"PROLOGUE_04","bgm":"BATTLE_DESIGNPLAZA_NIGHT","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"COMMANDER_EXILER_NULL_NULL","text":{"KOREA":"음?","JPN":"うん？","ENG":"Mmm?","TWN":"嗯？"},"stage":{"bg":"PROLOGUE_04","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"COMMANDER_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"비상 통로는 이쪽입니다. 소령님!","JPN":"非常通路はこちらです。少佐！","ENG":"The emergency passage is this way, Major!","TWN":"少校，緊急通道在這邊！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L39_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"이제 격벽만 해제하면, 밖으로 나갈 수 있습니다.","JPN":"あとは隔壁を解除すれば、外に出られます。","ENG":"We'll be able to go out once we unlock the wall.","TWN":"解除隔離牆後，我們就可以到外面去了！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"좋아요. 전 대원, 모두 조금만 더 힘냅시다! 부상자들을 부축해주세요!","JPN":"わかりました。全隊員、もう少しだけ頑張りましょう！　負傷者を支えてあげてください！","ENG":"Okay. Everyone, just a little more! Help the wounded!","TWN":"好，全體隊員，大家再撐一下！扶好傷患！"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"격벽 해제 완료하였습니다. 이제 이 통로만 지나면……","JPN":"隔壁の解除を完了しました。あとはこの通路を抜ければ……","ENG":"The wall's unlocked. Now, we just have to pass through–","TWN":"隔離牆已解除，現在只要通過通道……"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GUARD_EXILER_NPC_NULL","text":{"KOREA":"읏!?","JPN":"うっ！？","ENG":"Ngh?!","TWN":"呃！？"},"stage":{"bg":"WORKSHOP","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GUARD_EXILER_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>…….</color>","JPN":"<color=#ff3636>……</color>","ENG":"<color=#ff3636>...</color>","TWN":"<color=#ff3636>……</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_BREATH_MASK"},{"id":"L48_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>드디어 찾아냈군.</color>","JPN":"<color=#ff3636>やっと見つけた。</color>","ENG":"<color=#ff3636>I finally found you.</color>","TWN":"<color=#ff3636>終於找到了。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"아, 아, 아포리아!?","JPN":"あ、あ、アポリア！？","ENG":"A-A-Aporia?!","TWN":"阿，阿，阿波利亞？！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이거, 난감한데요?","JPN":"これは、困りましたね。","ENG":"This is not good...","TWN":"這個，情況不妙喔？"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이렇게 가까이서 직접 마주하는 건, 두 번째인 것 같은데……","JPN":"ここまで近い距離で対面するのは、二回目のような……","ENG":"I think this is the second time we've met up close like this...","TWN":"這樣近距離的面對面，好像是第二次了……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"처음과는 비교도 안 될 정도로 침식파가 강렬해졌어요.","JPN":"最初とは比べものにならないぐらい侵食波が強力になっています。","ENG":"But compared to the first, its Corruption ray has become ridiculously stronger.","TWN":"與第一次時相比，侵蝕波的猛烈程度大得離譜。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"로널드 박사님의 가정에 따르면 그동안 네피림의 핵을 흡수해왔기 때문이겠죠.","JPN":"ロナルド博士の仮説に沿って考えると、これまでネフィリムの核を吸収してきたからでしょうね。","ENG":"According to Dr. Ronald's hypothesis, it's because Aporia's been absorbing the Nephils' cores.","TWN":"根據羅那魯多·李博士的假設，那段時間還在吸收諾菲力核心。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"어쩌면 이미 5종에 도달했을지도 모르겠네요.","JPN":"もしかすると、すでに第5種に到達しているかもしれません。","ENG":"Perhaps he has already reached Category 5.","TWN":"或許現在已經達到5類侵蝕體也說不定。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LONE_EXILER_NPC_NULL","text":{"KOREA":"우, 우린 끝장이야. 여기서 모두 죽을 거라고.","JPN":"ぼ、僕たちはもう終わりだ。みんなここで死ぬんだ。","ENG":"W-we're doomed. We're all gonna die here.","TWN":"我，我們完蛋了。我們全部……都會死在這裡。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LONE_EXILER_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"이제 어떻게 할까요, 카린 양.","JPN":"さあ、どうしますか、カリンさん。","ENG":"What should we do now, Karin?","TWN":"現在該怎麼辦，卡琳。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"긍지 높은 델타 세븐의 일원으로서……","JPN":"誇り高きデルタセブンの一員として……","ENG":"As a proud member of Delta Seven...","TWN":"我要你作為榮耀第七三角洲部隊的一員……"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_KING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"살아라……!","JPN":"生き延びろ……！","ENG":"Live...!","TWN":"活下去……！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_KING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"마지막의…… 마지막 순간까지…… 포기하지 말고 반드시 살아남아라!","JPN":"最後の……最後の瞬間まで……諦めずに必ず生き延びろ！","ENG":"Until... the very last second... Don't give up and survive no matter what!","TWN":"你要堅持……到最後一刻……不能放棄，一定要活下去！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_KING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"JAKE_DELTA_NULL_NULL","text":{"KOREA":"살아서…… 우리의 세계를……!","JPN":"生きて……俺たちの世界を……！","ENG":"Survive... and protect–","TWN":"活下去……拯救我們的世……！"},"stage":{"bg":"BLACK","bgm":"THEMA_BOSS_KING","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"JAKE_DELTA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 싸울 겁니다.","JPN":"私は戦います。","ENG":"I will fight.","TWN":"我要戰鬥。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"마지막에 마지막 순간이 닥칠 때까지 절대 포기하지 않기로.","JPN":"最後の最後の瞬間になるまで、絶対に諦めないと。","ENG":"Until I draw my last breath, I will never give up.","TWN":"直到最後一刻，也不會放棄。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"대령님의 묘비 앞에서 그렇게 맹세했으니까요.","JPN":"大佐の墓石の前で誓いましたから。","ENG":"I swore in front of Colonel's grave.","TWN":"我在上校的墓碑前發過誓。"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_AP_NULL","text":{"KOREA":"카린 양…….","JPN":"カリンさん……","ENG":"Karin...","TWN":"卡琳……"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"JOOSHIYOON_FENRIR_AP_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전략특수전 사령부 델타 세븐의 마지막 대원, 카린 웡 소령!","JPN":"戦略特殊戦司令部デルタセブンの最後の隊員、カリン・ウォン少佐！","ENG":"I, Major Karin Wong, am the last member of Delta Seven of the Strategic Special Operations Command!","TWN":"戰略特戰司令部第七三角洲部隊最後一名隊員，卡琳少校！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"저는 이 싸움, 결코 도망치지 않을 겁니다!","JPN":"この戦いから、私は決して逃げません！","ENG":"I shall not run away from this fight!","TWN":"這場戰鬥，我會堅持到底！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그래, 너희는……</color>","JPN":"<color=#ff3636>そうだ、お前らは……</color>","ENG":"<color=#ff3636>Yes, you're...</color>","TWN":"<color=#ff3636>沒錯，就是你們……</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L30_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>그렇게 몇 번이고, 몇 번이고 이 몸을 방해하더군.</color>","JPN":"<color=#ff3636>そうやって何度も何度も、俺の邪魔をしてきた。</color>","ENG":"<color=#ff3636>The ones who keep disturbing me over and over again.</color>","TWN":"<color=#ff3636>一次又一次地妨礙我。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>죽이고…… 또 죽여도 끝도 없이…….</color>","JPN":"<color=#ff3636>殺しても……また殺しても、ずっとだ……</color>","ENG":"<color=#ff3636>No matter... how many times I kill...</color>","TWN":"<color=#ff3636>殺了一個又一個……怎麼都殺不完……</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>슬슬 성가시던 참이었다.</color>","JPN":"<color=#ff3636>いい加減面倒くさくなってきたところだった。</color>","ENG":"<color=#ff3636>It is getting on my nerves.</color>","TWN":"<color=#ff3636>我開始厭煩了。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"KING_EXILER_NULL_NULL","text":{"KOREA":"<color=#ff3636>지금 이 자리에서, 단 한 마리도 남김없이 모두 끝내주지.</color>","JPN":"<color=#ff3636>今ここで、一匹残らず全員終わらせてやる。</color>","ENG":"<color=#ff3636>I will reduce everyone here to dust.</color>","TWN":"<color=#ff3636>就在這裡，把你們一個不剩地，全部解決掉。</color>"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KING_EXILER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"KYLE_DELTA_AP_NULL","text":{"KOREA":"전 대원, 전투 준비!","JPN":"全隊員、戦闘準備！","ENG":"All units! Prepare for battle!","TWN":"全體隊員，準備戰鬥！"},"stage":{"bg":"WORKSHOP","bgm":"THEMA_BOSS_KING","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KYLE_DELTA_AP_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"}]`);export{e as default};